mapper.update:
UPDATE t_car_cost_tabulation
SET amount = #{amount}
WHERE module_id = #{moduleId} AND module_type = #{moduleType}

UPDATE t_car_cost_tabulation
SET amount = #{amount},
    category_id = #{categoryId}
WHERE module_id = #{moduleId} AND module_type = #{moduleType}

mapper.select:
SELECT *
FROM t_car_cost_tabulation
WHERE driver_id = #{driverId} AND create_user_type = #{userType}
ORDER BY create_time DESC
LIMIT #{limitNum}

SELECT cct.*, w.waybill_number, v.vehicle_number, c.category_name FROM t_car_cost_tabulation cct LEFT JOIN t_waybill w ON cct.waybill_id = w.waybill_id LEFT JOIN t_vehicle v ON cct.vehicle_id = v.vehicle_id LEFT JOIN t_car_cost_category c ON cct.category_id = c.category_id WHERE cct.driver_id = #{queryForm.driverId} AND cct.create_user_type = #{queryForm.createUserType}
AND (INSTR(w.waybill_number, #{queryForm.keywords}) OR INSTR(v.vehicle_number, #{queryForm.keywords}))
AND cct.module_type = #{queryForm.moduleType}
AND cct.audit_status = #{queryForm.auditStatus}
ORDER BY create_time DESC

SELECT tabulation_id
FROM t_car_cost_tabulation
WHERE module_id = #{moduleId} AND module_type = #{moduleType}
